//! Request/response logging component.

use std::time::Duration;
use crate::{RichOutput, OutputMode};
use crate::themes::FastApiTheme;

/// HTTP method for styling
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum HttpMethod {
    Get, Post, Put, Patch, Delete, Head, Options, Trace, Connect,
}

impl HttpMethod {
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::Get => "GET",
            Self::Post => "POST",
            Self::Put => "PUT",
            Self::Patch => "PATCH",
            Self::Delete => "DELETE",
            Self::Head => "HEAD",
            Self::Options => "OPTIONS",
            Self::Trace => "TRACE",
            Self::Connect => "CONNECT",
        }
    }

    pub fn color(&self, theme: &FastApiTheme) -> &str {
        match self {
            Self::Get => theme.method_get_hex(),
            Self::Post => theme.method_post_hex(),
            Self::Put => theme.method_put_hex(),
            Self::Patch => theme.method_patch_hex(),
            Self::Delete => theme.method_delete_hex(),
            _ => theme.method_other_hex(),
        }
    }

    pub fn padded(&self) -> String {
        format!("{:7}", self.as_str())
    }
}

impl std::str::FromStr for HttpMethod {
    type Err = ();
    fn from_str(s: &str) -> Result<Self, ()> {
        match s.to_uppercase().as_str() {
            "GET" => Ok(Self::Get),
            "POST" => Ok(Self::Post),
            "PUT" => Ok(Self::Put),
            "PATCH" => Ok(Self::Patch),
            "DELETE" => Ok(Self::Delete),
            "HEAD" => Ok(Self::Head),
            "OPTIONS" => Ok(Self::Options),
            "TRACE" => Ok(Self::Trace),
            "CONNECT" => Ok(Self::Connect),
            _ => Err(()),
        }
    }
}

/// Request log entry.
#[derive(Debug, Clone)]
pub struct RequestLog {
    pub method: HttpMethod,
    pub path: String,
    pub status_code: u16,
    pub status_text: String,
    pub duration: Duration,
    pub request_headers: Vec<(String, String)>,
    pub response_headers: Vec<(String, String)>,
}

impl RequestLog {
    pub fn new(method: HttpMethod, path: &str, status_code: u16, duration: Duration) -> Self {
        Self {
            method,
            path: path.to_string(),
            status_code,
            status_text: status_text_for_code(status_code),
            duration,
            request_headers: Vec::new(),
            response_headers: Vec::new(),
        }
    }

    pub fn with_request_header(mut self, name: &str, value: &str) -> Self {
        self.request_headers.push((name.to_string(), value.to_string()));
        self
    }

    pub fn status_category(&self) -> StatusCategory {
        match self.status_code {
            100..=199 => StatusCategory::Info,
            200..=299 => StatusCategory::Success,
            300..=399 => StatusCategory::Redirect,
            400..=499 => StatusCategory::ClientError,
            500..=599 => StatusCategory::ServerError,
            _ => StatusCategory::Unknown,
        }
    }

    pub fn duration_ms(&self) -> f64 {
        self.duration.as_secs_f64() * 1000.0
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum StatusCategory {
    Info, Success, Redirect, ClientError, ServerError, Unknown,
}

fn status_text_for_code(code: u16) -> String {
    match code {
        200 => "OK".to_string(),
        201 => "Created".to_string(),
        204 => "No Content".to_string(),
        301 => "Moved".to_string(),
        302 => "Found".to_string(),
        400 => "Bad Request".to_string(),
        401 => "Unauthorized".to_string(),
        403 => "Forbidden".to_string(),
        404 => "Not Found".to_string(),
        422 => "Unprocessable".to_string(),
        500 => "Server Error".to_string(),
        _ => format!("{}", code),
    }
}

/// Request logger.
pub struct RequestLogger;

impl RequestLogger {
    /// Log a request in compact format.
    pub fn log_compact(log: &RequestLog, output: &RichOutput) {
        eprintln!("[DEBUG] RequestLogger::log_compact method={:?} path={} status={}",
            log.method, log.path, log.status_code);

        match output.mode() {
            OutputMode::Rich => Self::log_compact_rich(log, output),
            OutputMode::Plain | OutputMode::Minimal => Self::log_compact_plain(log, output),
        }
    }

    fn log_compact_plain(log: &RequestLog, output: &RichOutput) {
        let line = format!(
            "Request: {} {} -> {} {} {:.1}ms",
            log.method.as_str(),
            log.path,
            log.status_code,
            log.status_text,
            log.duration_ms()
        );
        output.print(&line);
    }

    fn log_compact_rich(log: &RequestLog, output: &RichOutput) {
        // Rich mode would use colors, but for now use plain
        Self::log_compact_plain(log, output);
    }

    /// Log a request in verbose format with headers.
    pub fn log_verbose(log: &RequestLog, output: &RichOutput) {
        eprintln!("[DEBUG] RequestLogger::log_verbose method={:?} path={}", log.method, log.path);

        match output.mode() {
            OutputMode::Rich => Self::log_verbose_rich(log, output),
            OutputMode::Plain | OutputMode::Minimal => Self::log_verbose_plain(log, output),
        }
    }

    fn log_verbose_plain(log: &RequestLog, output: &RichOutput) {
        output.print(&format!("Request: {} {}", log.method.as_str(), log.path));
        output.print(&format!("Status: {} {}", log.status_code, log.status_text));
        output.print(&format!("Time: {:.1}ms", log.duration_ms()));

        if !log.request_headers.is_empty() {
            output.print("Request-Headers:");
            for (name, value) in &log.request_headers {
                output.print(&format!("  {}: {}", name, value));
            }
        }
    }

    fn log_verbose_rich(log: &RequestLog, output: &RichOutput) {
        Self::log_verbose_plain(log, output);
    }
}
